class Solution:

    highest = 0

    def lengthOfLongestSubstring(self, s: str) -> int:
        for i in range(len(s)):
            print(i)
            for j in range(len(s)):
                if(j < i):
                    continue

                substring = Solution.get_substring(s, i, j)
                if(Solution.is_valid_substring(substring)):
                   if(self.highest <= len(substring)):
                        self.highest = len(substring)
                else:
                    break
        return self.highest


    @staticmethod
    def get_substring(s, start, end):
           s2 = s[start:end + 1]
           return s2

    @staticmethod
    def is_valid_substring(s):
        return len(set(s)) == len(s)

